def round_robin(processes, quantum):
    # processes: dict with pid as key, (arrival, burst) as value
    n = len(processes)
    remaining_bt = {p: processes[p][1] for p in processes}
    waiting_time = {p: 0 for p in processes}
    current_time = 0
    completed = 0
    ready_queue = []
    arrived = sorted(processes.keys())

    while completed < n:
        # Add newly arrived processes to queue
        for p in arrived:
            if processes[p][0] <= current_time and p not in ready_queue and remaining_bt[p] > 0:
                ready_queue.append(p)

        if not ready_queue:
            current_time += 1
            continue

        process = ready_queue.pop(0)

        if remaining_bt[process] <= quantum:
            current_time += remaining_bt[process]
            remaining_bt[process] = 0
            completed += 1
            turnaround = current_time - processes[process][0]
            waiting_time[process] = turnaround - processes[process][1]
        else:
            current_time += quantum
            remaining_bt[process] -= quantum
            # Add newly arrived and re-queue current
            for p in arrived:
                if processes[p][0] <= current_time and p not in ready_queue and remaining_bt[p] > 0:
                    ready_queue.append(p)
            ready_queue.append(process)

    return waiting_time

# Example usage
processes = {'P1': (0, 10), 'P2': (1, 5), 'P3': (2, 8)}
wt = round_robin(processes, 4)
print("Waiting times:", wt)

def priority_scheduling_with_aging(processes, aging_rate=1):
    # processes: dict {pid: (arrival, burst, priority)}
    n = len(processes)
    remaining_bt = {p: processes[p][1] for p in processes}
    base_priority = {p: processes[p][2] for p in processes}
    waiting_time = {p: 0 for p in processes}
    current_time = 0
    completed = 0
    completed_processes = []

    while completed < n:
        # Calculate effective priority with aging
        effective_priority = {}
        for p in processes:
            if remaining_bt[p] > 0:
                # Aging: reduce waiting time and increase priority
                aging_bonus = min(waiting_time[p] // 5 * aging_rate, 10)
                effective_priority[p] = base_priority[p] - aging_bonus
            else:
                effective_priority[p] = float('inf')

        # Select highest priority (lowest number)
        current_process = min(effective_priority, key=effective_priority.get)

        # Execute for 1 time unit
        current_time += 1
        remaining_bt[current_process] -= 1

        # Update waiting times
        for p in processes:
            if remaining_bt[p] > 0 and p != current_process:
                waiting_time[p] += 1

        if remaining_bt[current_process] == 0:
            completed += 1
            turnaround = current_time - processes[current_process][0]
            wt = turnaround - processes[current_process][1]
            completed_processes.append((current_process, wt, turnaround))

    return completed_processes

# Example: (arrival, burst, priority - lower is higher priority)
processes = {'P1': (0, 10, 3), 'P2': (0, 5, 5), 'P3': (0, 8, 2)}
results = priority_scheduling_with_aging(processes)
for r in results:
    print(f"{r[0]}: Waiting={r[1]}, Turnaround={r[2]}")
